const boardDiv = document.getElementById("board");
const historyDiv = document.getElementById("history");
const turnText = document.getElementById("turn");

let selected = null;

let whiteTime = 600;
let blackTime = 600;

let currentTurn = "white";

/* ---------- TIMER ---------- */

setInterval(() => {

    if (currentTurn === "white")
            whiteTime--;
                else
                        blackTime--;

                            updateTimer();

                            }, 1000);

                            function updateTimer() {

                                document.getElementById("whiteTimer").innerText = formatTime(whiteTime);
                                    document.getElementById("blackTimer").innerText = formatTime(blackTime);

                                    }

                                    function formatTime(t) {

                                        let m = Math.floor(t / 60);
                                            let s = t % 60;

                                                return m + ":" + (s < 10 ? "0" : "") + s;

                                                }

                                                /* ---------- BOARD ---------- */

                                                function loadBoard() {

                                                    fetch("/api/game/board")
                                                            .then(res => res.json())
                                                                    .then(board => drawBoard(board));

                                                                    }

                                                                    function drawBoard(board) {

                                                                        boardDiv.innerHTML = "";

                                                                            for (let r = 0; r < 8; r++) {

                                                                                    for (let c = 0; c < 8; c++) {

                                                                                                const sq = document.createElement("div");

                                                                                                            sq.className = "square";

                                                                                                                        if ((r + c) % 2 === 0)
                                                                                                                                        sq.classList.add("light");
                                                                                                                                                    else
                                                                                                                                                                    sq.classList.add("dark");

                                                                                                                                                                                sq.dataset.row = r;
                                                                                                                                                                                            sq.dataset.col = c;

                                                                                                                                                                                                        sq.onclick = squareClick;

                                                                                                                                                                                                                    const piece = board[r][c];

                                                                                                                                                                                                                                if (piece) {

                                                                                                                                                                                                                                                const img = document.createElement("img");

                                                                                                                                                                                                                                                                img.src = "/pieces/" + piece + ".svg";

                                                                                                                                                                                                                                                                                img.className = "piece";

                                                                                                                                                                                                                                                                                                sq.appendChild(img);
                                                                                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                                                                                        boardDiv.appendChild(sq);
                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                                                                                    /* ---------- MOVE ---------- */

                                                                                                                                                                                                                                                                                                                                    function squareClick() {

                                                                                                                                                                                                                                                                                                                                        const r = this.dataset.row;
                                                                                                                                                                                                                                                                                                                                            const c = this.dataset.col;

                                                                                                                                                                                                                                                                                                                                                if (!selected) {

                                                                                                                                                                                                                                                                                                                                                        selected = { r, c };
                                                                                                                                                                                                                                                                                                                                                                this.style.outline = "3px solid red";

                                                                                                                                                                                                                                                                                                                                                                    } else {

                                                                                                                                                                                                                                                                                                                                                                            movePiece(selected.r, selected.c, r, c);
                                                                                                                                                                                                                                                                                                                                                                                    selected = null;
                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                                                                                                        function movePiece(fr, fc, tr, tc) {

                                                                                                                                                                                                                                                                                                                                                                                            fetch("/api/move", {

                                                                                                                                                                                                                                                                                                                                                                                                    method: "POST",

                                                                                                                                                                                                                                                                                                                                                                                                            headers: {
                                                                                                                                                                                                                                                                                                                                                                                                                        "Content-Type": "application/json"
                                                                                                                                                                                                                                                                                                                                                                                                                                },

                                                                                                                                                                                                                                                                                                                                                                                                                                        body: JSON.stringify({

                                                                                                                                                                                                                                                                                                                                                                                                                                                    fromRow: parseInt(fr),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                fromCol: parseInt(fc),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                            toRow: parseInt(tr),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        toCol: parseInt(tc)

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                })

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    })
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            .then(res => res.json())
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    .then(() => {

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                loadBoard();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            loadHistory();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        loadTurn();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                /* ---------- HISTORY ---------- */

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                function loadHistory() {

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    fetch("/api/game/history")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            .then(res => res.json())
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    .then(list => {

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                historyDiv.innerHTML = "";

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            list.forEach(m => {

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const li = document.createElement("li");

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            li.innerText = m;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            historyDiv.appendChild(li);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                /* ---------- TURN ---------- */

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                function loadTurn() {

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    fetch("/api/game/turn")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            .then(res => res.text())
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    .then(t => {

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                currentTurn = t;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            turnText.innerText = "Turn: " + t;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    /* ---------- RESET ---------- */

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    function resetGame() {

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        fetch("/api/game/reset", { method: "POST" })
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                .then(() => {

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            loadBoard();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        loadHistory();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    loadTurn();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                whiteTime = 600;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            blackTime = 600;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    /* ---------- UNDO ---------- */

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    function undoMove() {

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        fetch("/api/game/undo", { method: "POST" })
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                .then(() => {

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            loadBoard();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        loadHistory();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    loadTurn();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            /* ---------- START ---------- */

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            loadBoard();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            loadHistory();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            loadTurn();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            